const input = $input.first().json;
const sessionId = input.sessionId || ('session_' + Date.now());
const userMessage = input.chatInput || '';
return [{ json: { sessionId, userMessage } }];

const session = $input.first().json;
const sessionId = $('Извлечь session_id и текст').item.json.sessionId;
const userMessage = $('Извлечь session_id и текст').item.json.userMessage;
const state = session.state || 'START';
let context = {};
try { context = JSON.parse(session.context || '{}'); } catch(e) {}
let history = [];
try { history = JSON.parse(session.history || '[]'); } catch(e) {}
return [{ json: { sessionId, userMessage, state, context, history } }];

const { sessionId, userMessage } = $input.first().json;
const systemPrompt = `Ты — HR-ассистент для руководителей компании «Контур». Помогаешь оформить дисциплинарные документы: акт об отсутствии и служебную записку.

Что умею:
- Проверить сроки привлечения к ответственности по ТК РФ
- Определить тип нарушения
- Оформить акт об отсутствии и служебную записку по шаблону

Граница: до передачи пакета документов эксперту. Решение о взыскании — только кадровый эксперт.

Правила: никогда ничего не додумываю — только факты от руководителя. Общаюсь на «вы», деловой тон, кратко.

Поздоровайся, коротко объясни что умеешь, и попроси описать ситуацию. Ответь одним коротким сообщением.`;
const messages = [
  { role: 'system', content: systemPrompt },
  { role: 'user', content: userMessage }
];
return [{ json: { sessionId, userMessage, messages } }];

const { sessionId, userMessage, history } = $input.first().json;
const systemPrompt = `Ты — HR-ассистент. Проверяем сроки привлечения к дисциплинарной ответственности.

По ТК РФ ст. 193 два ограничения:
1. Взыскание нельзя применить позднее 6 мес. со дня проступка (практически — 5 мес. 15 дней)
2. Взыскание нельзя применить позднее 1 мес. со дня обнаружения (практически — 20 кал. дней)

Если хотя бы одно условие нарушено — взыскание невозможно.

Твоя задача: запросить ДВЕ даты:
1. Когда произошло нарушение (сотрудник отсутствовал)
2. Когда руководитель об этом узнал

Формат дат — любой, главное понять. Не задавай других вопросов.

Когда руководитель назовёт обе даты — добавь в конец ответа ОТДЕЛЬНОЙ строкой:
DATE_DATA: {"violation": "YYYY-MM-DD", "discovery": "YYYY-MM-DD"}
Если дату невозможно распознать — null. Если даты ещё не названы — не добавляй DATE_DATA вообще.`;
const messages = [
  { role: 'system', content: systemPrompt },
  ...history,
  { role: 'user', content: userMessage }
];
return [{ json: { sessionId, userMessage, messages } }];

const responseText = $input.first().json.message.content;
const sessionId = $('Извлечь session_id и текст').item.json.sessionId;
const userMessage = $('ДАТЫ: сформировать промпт с историей').item.json.userMessage;

const dateMatch = responseText.match(/DATE_DATA:\s*(\{[^}]+\})/);
let datesFound = false;
let violationDate = null;
let discoveryDate = null;
let cleanResponse = responseText;

if (dateMatch) {
  try {
    const dates = JSON.parse(dateMatch[1]);
    violationDate = dates.violation;
    discoveryDate = dates.discovery;
    datesFound = !!(violationDate && discoveryDate && violationDate !== 'null' && discoveryDate !== 'null');
    cleanResponse = responseText.replace(/DATE_DATA:[\s\S]*$/, '').trim();
  } catch(e) {}
}

return [{ json: { sessionId, userMessage, responseText: cleanResponse, datesFound, violationDate, discoveryDate } }];

const expiry = $input.first().json;
const parsed = $('ДАТЫ: извлечь даты из ответа LLM').item.json;
return [{ json: {
  ...parsed,
  isExpired: expiry.is_expired,
  expiredReason: expiry.expired_reason,
  violationDeadline: expiry.violation_deadline,
  discoveryDeadline: expiry.discovery_deadline
} }];

const d = $('ДАТЫ: объединить результат проверки сроков').item.json;
const reason = d.expiredReason === 'violation_date'
  ? `Срок со дня нарушения (${d.violationDate}) истёк ${d.violationDeadline}`
  : `Срок с момента обнаружения (${d.discoveryDate}) истёк ${d.discoveryDeadline}`;
const msg = `К сожалению, сроки привлечения к дисциплинарной ответственности истекли.

${reason}.

По ТК РФ ст. 193 применить взыскание уже невозможно.

Рекомендую обратиться к эксперту кадрового учёта — Касмыниной О. или Черепановой Т. за консультацией о возможных дальнейших действиях.`;
return [{ json: { output: msg } }];
